1	const std = @import("std");
2	
3	/// Protocol version. Incremented on breaking changes.
4	pub const version: u32 = 1;
5	
6	/// Maximum message payload size.
7	pub const max_payload: usize = 65536;
8	
9	/// Message types sent between client and server.
10	pub const MessageType = enum(u16) {
11	    // Client -> Server
12	    identify = 100,
13	    command = 101,
14	    resize = 102,
15	    key = 103,
16	    shell = 104,
17	    exit = 105,
18	    exiting = 106,
19	
20	    // Server -> Client
21	    version = 200,
22	    ready = 201,
23	    output = 202,
24	    pause = 203,
25	    detach = 204,
26	    shutdown = 205,
27	    error_msg = 206,
28	    exit_ack = 207,
29	};
30	
31	/// Wire format header for all messages.
32	pub const Header = extern struct {
33	    msg_type: u16 align(1),
34	    payload_len: u32 align(1),
35	    flags: u16 align(1),
36	};
37	
38	pub const Message = struct {
39	    msg_type: MessageType,
40	    flags: u16,
41	    payload: []u8,
42	    allocator: std.mem.Allocator,
43	
44	    pub fn deinit(self: *Message) void {
45	        self.allocator.free(self.payload);
46	        self.* = undefined;
47	    }
48	};
49	
50	comptime {
51	    std.debug.assert(@sizeOf(Header) == 8);
52	}
53	
54	/// Identification message sent by client on connect.
55	pub const IdentifyMsg = extern struct {
56	    protocol_version: u32 align(1),
57	    pid: i32 align(1),
58	    flags: IdentifyFlags align(1),
59	    term_name: [64]u8 align(1),
60	    tty_name: [64]u8 align(1),
61	    cols: u16 align(1),
62	    rows: u16 align(1),
63	    xpixel: u16 align(1),
64	    ypixel: u16 align(1),
65	};
66	
67	pub const IdentifyFlags = packed struct(u32) {
68	    utf8: bool = false,
69	    control_mode: bool = false,
70	    terminal_256: bool = false,
71	    _padding: u29 = 0,
72	};
73	
74	pub const ResizeMsg = extern struct {
75	    cols: u16 align(1),
76	    rows: u16 align(1),
77	    xpixel: u16 align(1),
78	    ypixel: u16 align(1),
79	};
80	
81	pub const KeyMsg = extern struct {
82	    key: u64 align(1),
83	    mouse_x: u16 align(1),
84	    mouse_y: u16 align(1),
85	    mouse_button: u8 align(1),
86	    mouse_flags: u8 align(1),
87	};
88	
89	pub fn serializeHeader(header: Header) [8]u8 {
90	    var buf: [8]u8 = undefined;
91	    std.mem.writeInt(u16, buf[0..2], header.msg_type, .little);
92	    std.mem.writeInt(u32, buf[2..6], header.payload_len, .little);
93	    std.mem.writeInt(u16, buf[6..8], header.flags, .little);
94	    return buf;
95	}
96	
97	pub fn deserializeHeader(buf: *const [8]u8) Header {
98	    return .{
99	        .msg_type = std.mem.readInt(u16, buf[0..2], .little),
100	        .payload_len = std.mem.readInt(u32, buf[2..6], .little),
101	        .flags = std.mem.readInt(u16, buf[6..8], .little),
102	    };
103	}
104	
105	pub fn messageTypeFromInt(raw: u16) !MessageType {
106	    return switch (raw) {
107	        @intFromEnum(MessageType.identify) => .identify,
108	        @intFromEnum(MessageType.command) => .command,
109	        @intFromEnum(MessageType.resize) => .resize,
110	        @intFromEnum(MessageType.key) => .key,
111	        @intFromEnum(MessageType.shell) => .shell,
112	        @intFromEnum(MessageType.exit) => .exit,
113	        @intFromEnum(MessageType.exiting) => .exiting,
114	        @intFromEnum(MessageType.version) => .version,
115	        @intFromEnum(MessageType.ready) => .ready,
116	        @intFromEnum(MessageType.output) => .output,
117	        @intFromEnum(MessageType.pause) => .pause,
118	        @intFromEnum(MessageType.detach) => .detach,
119	        @intFromEnum(MessageType.shutdown) => .shutdown,
120	        @intFromEnum(MessageType.error_msg) => .error_msg,
121	        @intFromEnum(MessageType.exit_ack) => .exit_ack,
122	        else => error.InvalidMessageType,
123	    };
124	}
125	
126	pub fn writeAll(fd: std.posix.fd_t, bytes: []const u8) !void {
127	    var written: usize = 0;
128	    while (written < bytes.len) {
129	        const rc = std.c.write(fd, bytes[written..].ptr, bytes.len - written);
130	        if (rc < 0) switch (std.posix.errno(rc)) {
131	            .INTR, .AGAIN => continue,
132	            else => return error.WriteFailed,
133	        };
134	        if (rc == 0) return error.WriteFailed;
135	        written += @intCast(rc);
136	    }
137	}
138	
139	pub fn readExact(fd: std.posix.fd_t, buf: []u8) !void {
140	    var read_total: usize = 0;
141	    while (read_total < buf.len) {
142	        const rc = std.c.read(fd, buf[read_total..].ptr, buf.len - read_total);
143	        if (rc < 0) switch (std.posix.errno(rc)) {
144	            .INTR, .AGAIN => continue,
145	            else => return error.ReadFailed,
146	        };
147	        if (rc == 0) return error.UnexpectedEof;
148	        read_total += @intCast(rc);
149	    }
150	}
151	
152	pub fn sendMessage(fd: std.posix.fd_t, msg_type: MessageType, payload: []const u8) !void {
153	    return sendMessageWithFlags(fd, msg_type, 0, payload);
154	}
155	
156	pub fn sendMessageWithFlags(fd: std.posix.fd_t, msg_type: MessageType, flags: u16, payload: []const u8) !void {
157	    if (payload.len > max_payload) return error.PayloadTooLarge;
158	
159	    const header_bytes = serializeHeader(.{
160	        .msg_type = @intFromEnum(msg_type),
161	        .payload_len = @intCast(payload.len),
162	        .flags = flags,
163	    });
164	    try writeAll(fd, &header_bytes);
165	    if (payload.len > 0) {
166	        try writeAll(fd, payload);
167	    }
168	}
169	
170	pub fn recvHeader(fd: std.posix.fd_t) !Header {
171	    var buf: [8]u8 = undefined;
172	    try readExact(fd, &buf);
173	    return deserializeHeader(&buf);
174	}
175	
176	pub fn recvMessageAlloc(alloc: std.mem.Allocator, fd: std.posix.fd_t) !Message {
177	    const header = try recvHeader(fd);
178	    const msg_type = try messageTypeFromInt(header.msg_type);
179	    if (header.payload_len > max_payload) return error.PayloadTooLarge;
180	
181	    const payload = try alloc.alloc(u8, header.payload_len);
182	    errdefer alloc.free(payload);
183	    if (payload.len > 0) {
184	        try readExact(fd, payload);
185	    }
186	
187	    return .{
188	        .msg_type = msg_type,
189	        .flags = header.flags,
190	        .payload = payload,
191	        .allocator = alloc,
192	    };
193	}
194	
195	pub fn encodeCommandArgs(alloc: std.mem.Allocator, args: []const []const u8) ![]u8 {
196	    var total: usize = 0;
197	    for (args) |arg| total += arg.len + 1;
198	    if (total > max_payload) return error.PayloadTooLarge;
199	
200	    const payload = try alloc.alloc(u8, total);
