20	
21	/// Command execution context.
22	pub const Context = struct {
23	    server: *Server,
24	    session: ?*Session,
25	    window: ?*Window,
26	    pane: ?*Pane,
27	    client_index: ?usize = null,
28	    allocator: std.mem.Allocator,
29	    reply_fd: ?std.c.fd_t = null,
30	    registry: ?*const Registry = null,
31	    binding_manager: ?*binding_mod.BindingManager = null,
32	};
33	
34	/// Command handler function type.
35	pub const Handler = *const fn (ctx: *Context, args: []const []const u8) CmdError!void;
36	
37	pub const CmdError = error{
38	    InvalidArgs,
39	    SessionNotFound,
40	    WindowNotFound,
41	    PaneNotFound,
42	    BufferNotFound,
43	    CommandFailed,
44	    OutOfMemory,
45	};
46	
47	/// A registered command.
48	pub const CommandDef = struct {
49	    name: []const u8,
50	    alias: ?[]const u8,
51	    min_args: u8,
52	    max_args: u8,
53	    usage: []const u8,
54	    handler: Handler,
55	};
56	
57	/// Command registry.
58	pub const Registry = struct {
59	    commands: std.StringHashMap(CommandDef),
60	
61	    pub fn init(alloc: std.mem.Allocator) Registry {
62	        return .{ .commands = std.StringHashMap(CommandDef).init(alloc) };
63	    }
64	
65	    pub fn deinit(self: *Registry) void {
66	        self.commands.deinit();
67	    }
68	
69	    pub fn register(self: *Registry, def: CommandDef) !void {
70	        try self.commands.put(def.name, def);
71	        if (def.alias) |alias| {
72	            try self.commands.put(alias, def);
73	        }
74	    }
75	
76	    pub fn find(self: *const Registry, name: []const u8) ?CommandDef {
77	        return self.commands.get(name);
78	    }
79	
80	    /// Return a sorted, deduplicated list of all commands (aliases excluded).
81	    pub fn listAll(self: *const Registry, alloc: std.mem.Allocator) ![]CommandDef {
82	        var seen = std.StringHashMap(void).init(alloc);
83	        defer seen.deinit();
84	        var list: std.ArrayListAligned(CommandDef, null) = .empty;
85	        defer list.deinit(alloc);
86	
87	        var iter = self.commands.iterator();
88	        while (iter.next()) |entry| {
89	            const def = entry.value_ptr.*;
90	            if (seen.contains(def.name)) continue;
91	            try seen.put(def.name, {});
92	            try list.append(alloc, def);
93	        }
94	
95	        const items = try alloc.dupe(CommandDef, list.items);
96	        std.mem.sort(CommandDef, items, {}, struct {
97	            fn lessThan(_: void, a: CommandDef, b: CommandDef) bool {
98	                return std.mem.order(u8, a.name, b.name) == .lt;
99	            }
100	        }.lessThan);
101	        return items;
102	    }
103	
104	    /// Execute a command by name with arguments.
105	    pub fn execute(self: *const Registry, ctx: *Context, name: []const u8, args: []const []const u8) CmdError!void {
106	        const def = self.find(name) orelse return CmdError.CommandFailed;
107	        if (args.len < def.min_args or (def.max_args > 0 and args.len > def.max_args)) {
108	            return CmdError.InvalidArgs;
109	        }
110	        return def.handler(ctx, args);
111	    }
112	
113	    pub fn executeParsed(self: *const Registry, ctx: *Context, command: *const config_parser.Command) CmdError!void {
114	        return self.execute(ctx, command.name, command.args.items);
115	    }
116	
117	    /// Register all built-in commands.
118	    pub fn registerBuiltins(self: *Registry) !void {
119	        // -- Session commands --
120	        try self.register(.{ .name = "attach-session", .alias = "attach", .min_args = 0, .max_args = 10, .usage = "attach-session (attach) [-dErx] [-c working-directory] [-f flags] [-t target-session]", .handler = cmdAttachSession });
121	        try self.register(.{ .name = "detach-client", .alias = "detach", .min_args = 0, .max_args = 8, .usage = "detach-client (detach) [-aP] [-E shell-command] [-s target-session] [-t target-client]", .handler = cmdDetachClient });
122	        try self.register(.{ .name = "has-session", .alias = "has", .min_args = 0, .max_args = 2, .usage = "has-session (has) [-t target-session]", .handler = cmdHasSession });
123	        try self.register(.{ .name = "kill-server", .alias = null, .min_args = 0, .max_args = 0, .usage = "kill-server", .handler = cmdKillServer });
124	        try self.register(.{ .name = "kill-session", .alias = null, .min_args = 0, .max_args = 4, .usage = "kill-session [-aC] [-t target-session]", .handler = cmdKillSession });
125	        try self.register(.{ .name = "list-clients", .alias = "lsc", .min_args = 0, .max_args = 8, .usage = "list-clients (lsc) [-F format] [-f filter] [-O order] [-t target-session]", .handler = cmdListClients });
126	        try self.register(.{ .name = "list-commands", .alias = "lscm", .min_args = 0, .max_args = 4, .usage = "list-commands (lscm) [-F format] [command]", .handler = cmdListCommands });
127	        try self.register(.{ .name = "list-sessions", .alias = "ls", .min_args = 0, .max_args = 8, .usage = "list-sessions (ls) [-r] [-F format] [-f filter] [-O order]", .handler = cmdListSessions });
128	        try self.register(.{ .name = "lock-client", .alias = "lockc", .min_args = 0, .max_args = 2, .usage = "lock-client (lockc) [-t target-client]", .handler = cmdLockClient });
129	        try self.register(.{ .name = "lock-server", .alias = "lock", .min_args = 0, .max_args = 0, .usage = "lock-server (lock)", .handler = cmdLockServer });
130	        try self.register(.{ .name = "lock-session", .alias = "locks", .min_args = 0, .max_args = 2, .usage = "lock-session (locks) [-t target-session]", .handler = cmdLockSession });
131	        try self.register(.{ .name = "new-session", .alias = "new", .min_args = 0, .max_args = 20, .usage = "new-session (new) [-AdDEPX] [-c start-directory] [-e environment] [-F format] [-f flags] [-n window-name] [-s session-name] [-t target-session] [-x width] [-y height] [shell-command [argument ...]]", .handler = cmdNewSession });
132	        try self.register(.{ .name = "refresh-client", .alias = "refresh", .min_args = 0, .max_args = 20, .usage = "refresh-client (refresh) [-cDlLRSU] [-A pane:state] [-B name:what:format] [-C XxY] [-f flags] [-r pane:report] [-t target-client] [adjustment]", .handler = cmdRefreshClient });
