107	const Flags = struct {
108	    force_256: bool = false,
109	    control_mode: bool = false,
110	    shell_command: ?[:0]const u8 = null,
111	    no_daemon: bool = false,
112	    config_file: ?[:0]const u8 = null,
113	    socket_name: ?[:0]const u8 = null,
114	    socket_path: ?[:0]const u8 = null,
115	    utf8_flag: bool = false,
116	    verbose: u8 = 0,
117	    print_version: bool = false,
118	    print_help: bool = false,
119	    remaining: std.ArrayListAligned([:0]const u8, null),
120	
121	    fn deinit(self: *Flags, alloc: std.mem.Allocator) void {
122	        self.remaining.deinit(alloc);
123	    }
124	};
125	
126	fn getenv(name: [:0]const u8) ?[]const u8 {
127	    const value = std.c.getenv(name) orelse return null;
128	    return std.mem.sliceTo(value, 0);
129	}
