131	fn parseArgs(alloc: std.mem.Allocator, init_args: std.process.Args) Flags {
132	    var flags = Flags{ .remaining = .empty };
133	    var args = std.process.Args.Iterator.init(init_args);
134	    _ = args.next();
135	
136	    while (args.next()) |arg| {
137	        if (arg.len < 2 or arg[0] != '-') {
138	            flags.remaining.append(alloc, arg) catch {};
139	            while (args.next()) |rest| {
140	                flags.remaining.append(alloc, rest) catch {};
141	            }
142	            break;
143	        }
144	        for (arg[1..]) |c| {
145	            switch (c) {
146	                '2' => flags.force_256 = true,
147	                'C' => flags.control_mode = true,
148	                'D' => flags.no_daemon = true,
149	                'u' => flags.utf8_flag = true,
150	                'v' => flags.verbose +|= 1,
151	                'V' => flags.print_version = true,
152	                'h' => flags.print_help = true,
153	                'c' => {
154	                    flags.shell_command = args.next();
155	                    break;
156	                },
157	                'f' => {
158	                    flags.config_file = args.next();
159	                    break;
160	                },
161	                'L' => {
162	                    flags.socket_name = args.next();
163	                    break;
164	                },
165	                'S' => {
166	                    flags.socket_path = args.next();
167	                    break;
168	                },
169	                else => {},
170	            }
171	        }
172	    }
173	    return flags;
174	}
175	
176	fn resolveSocketPath(alloc: std.mem.Allocator, flags: *const Flags) ![]u8 {
177	    if (flags.socket_path) |path| {
178	        return try alloc.dupe(u8, path);
179	    }
180	    if (getenv("AGENTMUX_SOCKET_PATH")) |path| {
181	        return try alloc.dupe(u8, path);
182	    }
183	
184	    const socket_dir = try platform.core.defaultSocketDir(alloc);
185	    defer alloc.free(socket_dir);
186	    const socket_name = if (flags.socket_name) |sn|
187	        sn
188	    else if (getenv("AGENTMUX_SOCKET_NAME")) |sn|
189	        sn
190	    else
191	        default_socket_name;
192	
193	    return try std.fmt.allocPrint(alloc, "{s}/agentmux-{d}/{s}", .{
194	        socket_dir,
195	        std.c.getuid(),
196	        socket_name,
197	    });
198	}
