204	fn runServer(alloc: std.mem.Allocator, socket_path: []const u8, daemonize_server: bool, config_file: ?[:0]const u8) !void {
205	    if (daemonize_server) {
206	        try signals.daemonize();
207	    }
208	    signals.SignalHandler.install();
209	    var server = try server_mod.Server.init(alloc, socket_path);
210	    defer server.deinit();
211	    if (config_file) |cf| server.config_file = cf;
212	    try server.listen();
213	    server.loadDefaultConfig();
214	    try server.run();
215	}
216	
217	fn waitForServer(alloc: std.mem.Allocator, socket_path: []const u8) !void {
218	    var attempt: usize = 0;
219	    while (attempt < 100) : (attempt += 1) {
220	        var probe = client_mod.Client.init(alloc, socket_path);
221	        if (probe.connect()) {
222	            probe.disconnect();
223	            return;
224	        } else |_| {
225	            var delay = std.c.timespec{
226	                .sec = 0,
227	                .nsec = 50 * std.time.ns_per_ms,
228	            };
229	            _ = std.c.nanosleep(&delay, null);
230	        }
231	    }
232	    return error.ServerStartTimeout;
233	}
234	
235	fn autostartServer(alloc: std.mem.Allocator, socket_path: []const u8, config_file: ?[:0]const u8) !void {
236	    const pid = std.c.fork();
237	    if (pid < 0) return error.ForkFailed;
238	    if (pid == 0) {
239	        detachStdio();
240	        runServer(std.heap.c_allocator, socket_path, false, config_file) catch {};
241	        std.c.exit(0);
242	    }
243	    try waitForServer(alloc, socket_path);
244	}
245	
246	fn detachStdio() void {
247	    _ = std.c.setsid();
248	    _ = std.c.close(0);
249	    _ = std.c.close(1);
250	    _ = std.c.close(2);
251	
252	    const devnull: [*:0]const u8 = "/dev/null";
253	    const fd = std.c.open(devnull, .{ .ACCMODE = .RDWR }, @as(std.c.mode_t, 0));
254	    if (fd < 0) return;
255	    _ = std.c.dup2(fd, 0);
256	    _ = std.c.dup2(fd, 1);
257	    _ = std.c.dup2(fd, 2);
258	    if (fd > 2) _ = std.c.close(fd);
259	}
260	
261	fn runCommandMode(alloc: std.mem.Allocator, flags: *const Flags, socket_path: []const u8) !void {
262	    var client = client_mod.Client.init(alloc, socket_path);
263	    client.connect() catch |err| switch (err) {
264	        error.ConnectFailed => {
265	            try autostartServer(alloc, socket_path, flags.config_file);
266	            try client.connect();
267	        },
268	        else => return err,
269	    };
270	    defer client.disconnect();
271	
272	    var cols: u16 = 80;
273	    var rows: u16 = 24;
274	    if (client_terminal.getTerminalSize(0)) |ts| {
275	        cols = ts.cols;
276	        rows = ts.rows;
277	    }
278	    try client.identify(determineTerminalName(), cols, rows);
279	    const result = try client.requestCommand(flags.remaining.items);
280	    if (result.attached) {
281	        try client.interactiveLoop();
282	        return;
283	    }
284	    if (result.exit_code != 0) {
285	        std.c.exit(result.exit_code);
286	    }
287	}
