289	pub fn main(init: std.process.Init.Minimal) !void {
290	    var agentmux_alloc = core.allocator_mod.AgentmuxAllocator.init();
291	    defer agentmux_alloc.deinit();
292	    const alloc = agentmux_alloc.allocator();
293	
294	    var flags = parseArgs(alloc, init.args);
295	    defer flags.deinit(alloc);
296	
297	    if (flags.print_help) {
298	        writeStdout(
299	            \\usage: agentmux [-2CDhuVv] [-c shell-command] [-f file] [-L socket-name]
300	            \\                [-S socket-path] [command [flags]]
301	            \\
302	            \\options:
303	            \\  -2            Force 256-color terminal
304	            \\  -C            Start in control mode
305	            \\  -c command    Execute shell-command using the default shell
306	            \\  -D            Do not start the server as a daemon
307	            \\  -f file       Specify an alternative configuration file
308	            \\  -h            Show this help message
309	            \\  -L name       Use a different socket name (default: default)
310	            \\  -S path       Specify a full alternative path to the server socket
311	            \\  -u            Set the client to UTF-8 mode
312	            \\  -V            Print version and exit
313	            \\  -v            Enable verbose logging (repeat for more)
314	            \\
315	            \\commands:
316	            \\  Run 'agentmux list-commands' for a list of available commands.
317	            \\
318	        );
319	        return;
320	    }
321	
322	    if (flags.print_version) {
323	        writeStdout(version_string ++ "\n");
324	        return;
325	    }
326	
327	    const log_level: log.Level = switch (flags.verbose) {
328	        0 => .info,
329	        else => .debug,
330	    };
331	    log.init(log_level, null, flags.verbose > 0);
332	    defer log.deinit();
333	
334	    const socket_path = try resolveSocketPath(alloc, &flags);
335	    defer alloc.free(socket_path);
336	
337	    if (flags.remaining.items.len == 0) {
338	        // tmux-compatible default: create a new session and attach.
339	        // The server is auto-started by runCommandMode if needed.
340	        try flags.remaining.append(alloc, "new-session");
341	    }
342	
343	    try runCommandMode(alloc, &flags, socket_path);
344	}
