401	test "protocol command args preserve argument boundaries" {
402	    const alloc = std.testing.allocator;
403	    const args = [_][:0]const u8{ "display-message", "hello world" };
404	    const encoded = try protocol.encodeCommandArgs(alloc, &args);
405	    defer alloc.free(encoded);
406	    try std.testing.expectEqualStrings("display-message", encoded[0.."display-message".len]);
407	    try std.testing.expectEqual(@as(u8, 0), encoded["display-message".len]);
408	    try std.testing.expectEqualStrings("hello world", encoded["display-message".len + 1 .. encoded.len - 1]);
409	    try std.testing.expectEqual(@as(u8, 0), encoded[encoded.len - 1]);
410	}
