241	fn writeReplyMessage(ctx: *Context, msg_type: protocol.MessageType, message: []const u8) CmdError!void {
242	    if (ctx.reply_fd) |fd| {
243	        protocol.sendMessage(fd, msg_type, message) catch return CmdError.CommandFailed;
244	        return;
245	    }
246	
247	    const target_fd: std.c.fd_t = switch (msg_type) {
248	        .error_msg => 2,
249	        else => 1,
250	    };
251	    _ = std.c.write(target_fd, message.ptr, message.len);
252	}
253	
254	fn writeOutput(ctx: *Context, comptime fmt: []const u8, args: anytype) CmdError!void {
255	    var buf: [1024]u8 = undefined;
256	    const message = std.fmt.bufPrint(&buf, fmt, args) catch return CmdError.CommandFailed;
257	    try writeReplyMessage(ctx, .output, message);
258	}
259	
260	fn spawnWindowPane(alloc: std.mem.Allocator, shell: [:0]const u8, sx: u32, sy: u32) CmdError!*Pane {
261	    const pane = Pane.init(alloc, sx, sy) catch return CmdError.OutOfMemory;
262	    errdefer pane.deinit();
263	
264	    var pty = Pty.openPty() catch return CmdError.CommandFailed;
265	    pty.forkExec(shell, null) catch return CmdError.CommandFailed;
266	    pty.resize(@intCast(sx), @intCast(sy));
267	    pane.fd = pty.master_fd;
268	    pane.pid = pty.pid;
269	    return pane;
270	}
271	
272	fn parseTargetWindow(args: []const []const u8) ?u32 {
273	    var i: usize = 0;
274	    while (i < args.len) : (i += 1) {
275	        if (!std.mem.eql(u8, args[i], "-t") or i + 1 >= args.len) continue;
276	        i += 1;
277	        const target = args[i];
278	        if (target.len >= 2 and target[0] == ':') {
279	            return std.fmt.parseInt(u32, target[1..], 10) catch null;
280	        }
281	        return std.fmt.parseInt(u32, target, 10) catch null;
282	    }
283	    return null;
284	}
285	
286	fn defaultShell(session: ?*Session) [:0]const u8 {
287	    if (session) |s| return s.options.default_shell;
288	    return "/bin/sh";
289	}
