    const window = session.active_window orelse return CmdError.WindowNotFound;
    for (window.panes.items, 0..) |pane, i| {
        try writeOutput(ctx, "{d}: pane %{d} [{d}x{d}]\n", .{ i, pane.id, pane.sx, pane.sy });
    }
