250	    pub fn run(self: *Server) !void {
251	        const max_fds = 256;
252	        var pollfds: [max_fds]std.c.pollfd = undefined;
253	
254	        while (self.running) {
255	            if (signals.SignalHandler.shouldExit()) {
256	                self.stop();
257	                break;
258	            }
259	
260	            var nfds: usize = 0;
261	            if (self.listen_fd >= 0) {
262	                pollfds[nfds] = .{ .fd = self.listen_fd, .events = POLLIN, .revents = 0 };
263	                nfds += 1;
264	            }
265	
266	            for (self.clients.items) |client| {
267	                if (nfds >= max_fds) break;
268	                pollfds[nfds] = .{ .fd = client.fd, .events = POLLIN, .revents = 0 };
269	                nfds += 1;
270	            }
