272	            for (self.sessions.items) |session| {
273	                for (session.windows.items) |window| {
274	                    for (window.panes.items) |pane| {
275	                        if (nfds >= max_fds) break;
276	                        if (pane.fd >= 0) {
277	                            pollfds[nfds] = .{ .fd = pane.fd, .events = POLLIN, .revents = 0 };
278	                            nfds += 1;
279	                        }
280	                    }
281	                }
282	            }
283	
284	            const result = std.c.poll(pollfds[0..nfds].ptr, @intCast(nfds), 100);
285	            if (result < 0) continue;
286	            if (result == 0) continue;
287	
288	            if (nfds > 0 and pollfds[0].revents & POLLIN != 0) {
289	                self.acceptClient() catch {};
