291	
292	            var i: usize = if (self.listen_fd >= 0) 1 else 0;
293	            while (i < nfds) : (i += 1) {
294	                if (pollfds[i].revents & POLLIN == 0) continue;
295	                const fd = pollfds[i].fd;
