564	        const n = std.c.read(fd, &buf, buf.len);
565	        if (n <= 0) return;
566	
567	        const pane_state = self.session_loop.getPane(pane.id);
568	        if (pane_state) |ps| {
569	            ps.processPtyOutput(buf[0..@intCast(n)]);
570	        }
571	
572	        const session = self.findSessionForPaneFd(fd) orelse return;
573	        for (self.clients.items) |client| {
574	            if (client.session == session) {
575	                self.renderComposedToClient(client.fd, session, pane_state) catch {
576	                    // Fall back to raw relay on render failure.
577	                    protocol.sendMessage(client.fd, .output, buf[0..@intCast(n)]) catch {};
578	                };
579	            }
580	        }
581	    }
582	
583	    /// Render the composed terminal view (screen content + status bar) for a
584	    /// client.  Uses a pipe pair so the existing Output→fd writer can produce
585	    /// escape sequences that we then wrap in a protocol message.
586	    fn renderComposedToClient(
587	        self: *Server,
588	        client_fd: std.c.fd_t,
589	        session: *Session,
590	        pane_state_opt: ?*server_loop.PaneState,
591	    ) !void {
592	        const ps = pane_state_opt orelse return error.NoPaneState;
593	
594	        // Use a pipe so Output can flush to the write end while we
595	        // collect the bytes from the read end.
596	        var pipe_fds: [2]std.c.fd_t = undefined;
597	        if (std.c.pipe(&pipe_fds) != 0) return error.PipeFailed;
598	        defer _ = std.c.close(pipe_fds[0]);
599	        errdefer _ = std.c.close(pipe_fds[1]);
600	
601	        // Render dirty screen lines through the redraw pipeline.
602	        var out = output_mod.Output.init(pipe_fds[1]);
603	        ps.renderTo(&out);
604	
605	        // Render status bar on the last row.
606	        const window = session.active_window;
607	        const cols: u32 = if (window) |w| w.sx else 80;
608	        const rows: u32 = if (window) |w| w.sy else 24;
609	
610	        const fmt_ctx = status_fmt.FormatContext{
611	            .session_name = session.name,
612	            .window_name = if (window) |w| w.name else "",
613	        };
614	        const status_bar = @import("status/status.zig").StatusBar.init();
615	        const status_line = status_bar.render(self.allocator, cols, &fmt_ctx) catch null;
616	        defer if (status_line) |sl| self.allocator.free(sl);
617	
618	        if (status_line) |sl| {
619	            out.cursorTo(0, rows -| 1);
620	            out.attrReset();
621	            // Reverse video for status bar (like tmux default).
622	            out.writeBytes("\x1b[7m");
623	            out.writeBytes(sl);
624	            out.writeBytes("\x1b[0m");
625	        }
626	
627	        out.flush();
628	
629	        // Close write end so read gets EOF.
630	        _ = std.c.close(pipe_fds[1]);
631	        pipe_fds[1] = -1;
632	
633	        // Read rendered bytes from the pipe.
634	        var rendered: [protocol.max_payload]u8 = undefined;
635	        var total: usize = 0;
636	        while (total < rendered.len) {
637	            const rc = std.c.read(pipe_fds[0], rendered[total..].ptr, rendered.len - total);
638	            if (rc <= 0) break;
639	            total += @intCast(rc);
640	        }
641	
642	        if (total > 0) {
643	            try protocol.sendMessage(client_fd, .output, rendered[0..total]);
644	        }
645	    }
646	
647	    fn removeClient(self: *Server, client_idx: usize) void {
648	        if (client_idx >= self.clients.items.len) return;
649	        var client = self.clients.orderedRemove(client_idx);
650	        if (client.choose_tree_state) |*state| {
651	            state.deinit();
652	        }
653	        if (client.session) |session| {
654	            if (session.attached > 0) session.attached -= 1;
655	        }
656	        if (client.fd >= 0) _ = std.c.close(client.fd);
657	    }
658	
659	    fn ensureCommandSession(self: *Server, ctx: *cmd.Context, reply_fd: std.c.fd_t, command_name: []const u8, registry: *const cmd.Registry) !void {
660	        const canonical = if (registry.find(command_name)) |def| def.name else command_name;
661	        if (ctx.session != null or commandAllowsMissingSession(canonical)) return;
662	        if (self.default_session) |session| {
663	            ctx.session = session;
664	            return;
665	        }
666	        if (self.sessions.items.len == 1) {
667	            ctx.session = self.sessions.items[0];
668	            return;
669	        }
670	        if (self.sessions.items.len == 0) {
671	            try self.sendError(reply_fd, "no current session\n", 1);
672	            return error.CommandFailed;
673	        }
674	        try self.sendError(reply_fd, "ambiguous session; specify -t\n", 1);
675	        return error.CommandFailed;
676	    }
677	
678	    fn setClientSession(self: *Server, client_idx: usize, session: ?*Session) void {
679	        if (client_idx >= self.clients.items.len) return;
680	        const client = &self.clients.items[client_idx];
681	        if (client.session == session) return;
682	        if (client.session) |existing| {
683	            if (existing.attached > 0) existing.attached -= 1;
684	        }
685	        client.session = session;
686	        if (session) |current| {
687	            current.attached += 1;
688	        }
689	    }
690	
691	    fn findSessionForPaneFd(self: *Server, fd: std.c.fd_t) ?*Session {
692	        for (self.sessions.items) |session| {
693	            for (session.windows.items) |window| {
694	                for (window.panes.items) |pane| {
695	                    if (pane.fd == fd) return session;
696	                }
697	            }
698	        }
699	        return null;
700	    }
701	
702	    pub fn findPaneByFd(self: *Server, fd: std.c.fd_t) ?*Pane {
703	        for (self.sessions.items) |session| {
704	            for (session.windows.items) |window| {
705	                for (window.panes.items) |pane| {
706	                    if (pane.fd == fd) return pane;
707	                }
708	            }
709	        }
710	        return null;
711	    }
712	
713	    pub fn trackPane(self: *Server, pane: *Pane, cols: u32, rows: u32) !void {
714	        try self.session_loop.addPane(pane.id, pane.fd, cols, rows);
715	    }
716	
717	    pub fn untrackPane(self: *Server, pane_id: u32) void {
718	        self.session_loop.removePane(pane_id);
719	    }
720	
721	    fn ensureSocketDir(self: *Server) !void {
722	        if (std.mem.lastIndexOfScalar(u8, self.socket_path, '/')) |sep| {
723	            const dir = self.socket_path[0..sep];
724	            var dir_buf: [256]u8 = .{0} ** 256;
725	            if (dir.len < dir_buf.len) {
726	                @memcpy(dir_buf[0..dir.len], dir);
727	                _ = std.c.mkdir(@ptrCast(dir_buf[0..dir.len :0]), 0o700);
728	            }
729	        }
730	    }
731	
732	    fn removeStaleSocket(self: *Server) void {
733	        var path_buf: [256]u8 = .{0} ** 256;
734	        if (self.socket_path.len < path_buf.len) {
735	            @memcpy(path_buf[0..self.socket_path.len], self.socket_path);
736	            _ = std.c.unlink(@ptrCast(path_buf[0..self.socket_path.len :0]));
737	        }
738	    }
739	};
740	
741	fn commandAllowsMissingSession(name: []const u8) bool {
742	    return std.mem.eql(u8, name, "new-session") or
743	        std.mem.eql(u8, name, "list-sessions") or
744	        std.mem.eql(u8, name, "list-commands") or
745	        std.mem.eql(u8, name, "start-server") or
746	        std.mem.eql(u8, name, "kill-server") or
747	        std.mem.eql(u8, name, "display-message") or
748	        std.mem.eql(u8, name, "if-shell");
749	}
750	
751	fn commandErrorMessage(err: cmd.CmdError) []const u8 {
752	    return switch (err) {
753	        error.InvalidArgs => "invalid arguments\n",
754	        error.SessionNotFound => "session not found\n",
755	        error.WindowNotFound => "window not found\n",
756	        error.PaneNotFound => "pane not found\n",
757	        error.BufferNotFound => "buffer not found\n",
758	        error.CommandFailed => "command failed\n",
759	        error.OutOfMemory => "out of memory\n",
760	    };
761	}
762	
763	const POLLIN: i16 = 0x0001;
764	
765	test "commandAllowsMissingSession includes if-shell" {
766	    try std.testing.expect(commandAllowsMissingSession("if-shell"));
767	    try std.testing.expect(!commandAllowsMissingSession("send-prefix"));
768	}
