1204	fn cmdAttachSession(ctx: *Context, args: []const []const u8) CmdError!void {
1205	    const target: ?[]const u8 = parseNamedOption(args, "-t");
1206	    _ = parseNamedOption(args, "-c"); // start-dir: not used
1207	    _ = parseNamedOption(args, "-f"); // flags: not used
1208	
1209	    var detach_others = false;
1210	    for (args) |arg| {
1211	        if (std.mem.eql(u8, arg, "-d") or std.mem.eql(u8, arg, "-x")) detach_others = true;
1212	        // -E (no update-env), -r (read-only): parsed but not enforced
1213	    }
1214	
1215	    const session: *Session = if (target) |name|
1216	        ctx.server.findSession(name) orelse return CmdError.SessionNotFound
1217	    else if (ctx.server.sessions.items.len == 1)
1218	        ctx.server.sessions.items[0]
1219	    else if (ctx.server.default_session) |s|
1220	        s
1221	    else
1222	        return CmdError.SessionNotFound;
1223	
1224	    if (detach_others) {
1225	        for (ctx.server.clients.items, 0..) |client, i| {
1226	            if (client.session != session) continue;
1227	            if (ctx.client_index) |ci| if (ci == i) continue;
1228	            ctx.server.detachClient(i);
1229	        }
1230	    }
1231	
1232	    ctx.session = session;
1233	    ctx.server.default_session = session;
1234	}
