1255	fn cmdListCommands(ctx: *Context, args: []const []const u8) CmdError!void {
1256	    const registry = ctx.registry orelse return CmdError.CommandFailed;
1257	
1258	    // Single command lookup.
1259	    if (args.len > 0) {
1260	        const name = args[args.len - 1];
1261	        if (name.len > 0 and name[0] != '-') {
1262	            const def = registry.find(name) orelse {
1263	                try writeReplyMessage(ctx, .error_msg, "unknown command\n");
1264	                return CmdError.CommandFailed;
1265	            };
1266	            try writeOutput(ctx, "{s}\n", .{def.usage});
1267	            return;
1268	        }
1269	    }
1270	
1271	    // List all commands.
1272	    const all = registry.listAll(ctx.allocator) catch return CmdError.OutOfMemory;
1273	    defer ctx.allocator.free(all);
1274	    for (all) |def| {
1275	        try writeOutput(ctx, "{s}\n", .{def.usage});
1276	    }
1277	}
