1279	fn cmdLastPane(ctx: *Context, args: []const []const u8) CmdError!void {
1280	    const session = ctx.session orelse return CmdError.SessionNotFound;
1281	    var window = session.active_window orelse return CmdError.WindowNotFound;
1282	
1283	    var disable_input = false;
1284	    var enable_input = false;
1285	
1286	    var i: usize = 0;
1287	    while (i < args.len) : (i += 1) {
1288	        if (std.mem.eql(u8, args[i], "-d")) {
1289	            disable_input = true;
1290	        } else if (std.mem.eql(u8, args[i], "-e")) {
1291	            enable_input = true;
1292	        } else if (std.mem.eql(u8, args[i], "-Z")) {
1293	            // keep zoom: no special action needed
1294	        } else if (std.mem.eql(u8, args[i], "-t") and i + 1 < args.len) {
1295	            i += 1;
1296	            const target = args[i];
1297	            if (std.fmt.parseInt(u32, target, 10) catch null) |wnum| {
1298	                window = session.findWindowByNumber(wnum) orelse return CmdError.WindowNotFound;
1299	            }
1300	        }
1301	    }
1302	
1303	    window.prevPane();
1304	
1305	    if (disable_input) {
1306	        if (window.active_pane) |pane| pane.flags.input_disabled = true;
1307	    } else if (enable_input) {
1308	        if (window.active_pane) |pane| pane.flags.input_disabled = false;
1309	    }
1310	}
