1334	fn cmdSelectLayout(ctx: *Context, args: []const []const u8) CmdError!void {
1335	    const session = ctx.session orelse return CmdError.SessionNotFound;
1336	    var window = session.active_window orelse return CmdError.WindowNotFound;
1337	    var i: usize = 0;
1338	    while (i < args.len) : (i += 1) {
1339	        if (std.mem.eql(u8, args[i], "-t") and i + 1 < args.len) {
1340	            i += 1;
