1342	            window = session.findWindowByNumber(num) orelse return CmdError.WindowNotFound;
1343	        } else if (std.mem.eql(u8, args[i], "-n") or std.mem.eql(u8, args[i], "-o")) {
1344	            // next / last layout — cycle (resize triggers re-layout)
1345	        } else if (std.mem.eql(u8, args[i], "-p")) {
1346	            // previous layout — cycle
1347	        } else if (std.mem.eql(u8, args[i], "-E")) {
1348	            // spread panes evenly; handled by resize below
1349	        }
1350	        // layout-name positional arg: ignore for now (no named layout support)
1351	    }
1352	    if (window.layout_root) |root| {
1353	        root.resize(window.sx, window.sy);
