1357	fn cmdRotateWindow(ctx: *Context, args: []const []const u8) CmdError!void {
1358	    const session = ctx.session orelse return CmdError.SessionNotFound;
1359	    var window = session.active_window orelse return CmdError.WindowNotFound;
1360	    var direction: Window.SwapDirection = .next;
1361	    var zoom_after = false;
1362	    var i: usize = 0;
1363	    while (i < args.len) : (i += 1) {
1364	        if (std.mem.eql(u8, args[i], "-U")) {
1365	            direction = .prev;
1366	        } else if (std.mem.eql(u8, args[i], "-D")) {
1367	            direction = .next;
1368	        } else if (std.mem.eql(u8, args[i], "-Z")) {
1369	            zoom_after = true;
1370	        } else if (std.mem.eql(u8, args[i], "-t") and i + 1 < args.len) {
1371	            i += 1;
1372	            const num = std.fmt.parseInt(u32, args[i], 10) catch return CmdError.InvalidArgs;
1373	            window = session.findWindowByNumber(num) orelse return CmdError.WindowNotFound;
1374	        }
1375	    }
1376	    window.swapActivePane(direction);
1377	    if (zoom_after) _ = window.toggleZoom();
1378	}
