1380	fn cmdSwapWindow(ctx: *Context, args: []const []const u8) CmdError!void {
1381	    const session = ctx.session orelse return CmdError.SessionNotFound;
1382	    const src_name = parseNamedOption(args, "-s");
1383	    const dst_name = parseNamedOption(args, "-t");
1384	    var no_select = false;
1385	    for (args) |arg| {
1386	        if (std.mem.eql(u8, arg, "-d")) no_select = true;
1387	    }
1388	
1389	    const src_idx: usize = if (src_name) |name| blk: {
1390	        const num = std.fmt.parseInt(u32, name, 10) catch return CmdError.InvalidArgs;
1391	        const base = session.options.base_index;
1392	        break :blk if (num >= base) @intCast(num - base) else return CmdError.WindowNotFound;
1393	    } else if (session.active_window) |aw| blk: {
1394	        for (session.windows.items, 0..) |w, i| {
1395	            if (w == aw) break :blk i;
1396	        }
1397	        return CmdError.WindowNotFound;
1398	    } else return CmdError.WindowNotFound;
1399	
1400	    const dst_idx: usize = if (dst_name) |name| blk: {
1401	        const num = std.fmt.parseInt(u32, name, 10) catch return CmdError.InvalidArgs;
1402	        const base = session.options.base_index;
1403	        break :blk if (num >= base) @intCast(num - base) else return CmdError.WindowNotFound;
1404	    } else return CmdError.InvalidArgs;
1405	
1406	    if (src_idx >= session.windows.items.len or dst_idx >= session.windows.items.len) return CmdError.WindowNotFound;
1407	    const tmp = session.windows.items[src_idx];
1408	    session.windows.items[src_idx] = session.windows.items[dst_idx];
1409	    session.windows.items[dst_idx] = tmp;
1410	    if (!no_select) session.selectWindow(session.windows.items[dst_idx]);
1411	}
