1424	fn cmdBindKey(ctx: *Context, args: []const []const u8) CmdError!void {
1425	    const manager = ctx.binding_manager orelse {
1426	        try writeReplyMessage(ctx, .error_msg, "bind-key: no binding manager available\n");
1427	        return CmdError.CommandFailed;
1428	    };
1429	
1430	    var table_name: []const u8 = "prefix";
1431	    var repeat = false;
1432	    var note: ?[]const u8 = null;
1433	    var i: usize = 0;
1434	
1435	    // Parse flags: -T table, -n (root), -r (repeat), -N note
1436	    while (i < args.len) {
1437	        if (std.mem.eql(u8, args[i], "-T")) {
1438	            i += 1;
1439	            if (i >= args.len) return CmdError.InvalidArgs;
1440	            table_name = args[i];
1441	        } else if (std.mem.eql(u8, args[i], "-n")) {
1442	            table_name = "root";
1443	        } else if (std.mem.eql(u8, args[i], "-r")) {
1444	            repeat = true;
1445	        } else if (std.mem.eql(u8, args[i], "-N")) {
1446	            i += 1;
1447	            if (i >= args.len) return CmdError.InvalidArgs;
1448	            note = args[i];
1449	        } else {
1450	            break;
1451	        }
1452	        i += 1;
1453	    }
1454	
1455	    // Next arg is the key string
1456	    if (i >= args.len) return CmdError.InvalidArgs;
1457	    const kr = key_string.stringToKey(args[i]) orelse {
1458	        try writeReplyMessage(ctx, .error_msg, "bind-key: unknown key\n");
1459	        return CmdError.CommandFailed;
1460	    };
1461	    i += 1;
1462	
1463	    // Remaining args form the command
1464	    if (i >= args.len) return CmdError.InvalidArgs;
1465	    const cmd_parts = args[i..];
1466	
1467	    // Join command parts with spaces
1468	    var total_len: usize = 0;
1469	    for (cmd_parts, 0..) |part, idx| {
1470	        total_len += part.len;
1471	        if (idx < cmd_parts.len - 1) total_len += 1;
1472	    }
1473	    const cmd_str = ctx.allocator.alloc(u8, total_len) catch return CmdError.OutOfMemory;
1474	    defer ctx.allocator.free(cmd_str);
1475	    var pos: usize = 0;
1476	    for (cmd_parts, 0..) |part, idx| {
1477	        @memcpy(cmd_str[pos..][0..part.len], part);
1478	        pos += part.len;
1479	        if (idx < cmd_parts.len - 1) {
1480	            cmd_str[pos] = ' ';
1481	            pos += 1;
1482	        }
1483	    }
1484	
1485	    const table = manager.getOrCreateTable(table_name) catch return CmdError.OutOfMemory;
1486	    table.bindFull(kr.key, kr.mods, cmd_str, note, repeat) catch return CmdError.OutOfMemory;
1487	}
