1489	fn cmdUnbindKey(ctx: *Context, args: []const []const u8) CmdError!void {
1490	    const manager = ctx.binding_manager orelse {
1491	        try writeReplyMessage(ctx, .error_msg, "unbind-key: no binding manager available\n");
1492	        return CmdError.CommandFailed;
1493	    };
1494	
1495	    var table_name: []const u8 = "prefix";
1496	    var unbind_all = false;
1497	    var quiet = false;
1498	    var i: usize = 0;
1499	
1500	    // Parse flags: -T table, -n (root), -a (all), -q (quiet)
1501	    while (i < args.len) {
1502	        if (std.mem.eql(u8, args[i], "-T")) {
1503	            i += 1;
1504	            if (i >= args.len) return CmdError.InvalidArgs;
1505	            table_name = args[i];
1506	        } else if (std.mem.eql(u8, args[i], "-n")) {
1507	            table_name = "root";
1508	        } else if (std.mem.eql(u8, args[i], "-a")) {
1509	            unbind_all = true;
1510	        } else if (std.mem.eql(u8, args[i], "-q")) {
1511	            quiet = true;
1512	        } else {
1513	            break;
1514	        }
1515	        i += 1;
1516	    }
1517	
1518	    if (unbind_all) {
1519	        if (manager.tables.getPtr(table_name)) |table| {
1520	            for (table.bindings.items) |*b| {
1521	                switch (b.action) {
1522	                    .command => |cmd| table.allocator.free(cmd),
1523	                    .none => {},
1524	                }
1525	                if (b.note) |n| table.allocator.free(n);
1526	            }
1527	            table.bindings.clearRetainingCapacity();
1528	        }
1529	        return;
1530	    }
1531	
1532	    if (i >= args.len) return CmdError.InvalidArgs;
1533	    const kr = key_string.stringToKey(args[i]) orelse {
1534	        if (quiet) return;
1535	        try writeReplyMessage(ctx, .error_msg, "unbind-key: unknown key\n");
1536	        return CmdError.CommandFailed;
1537	    };
1538	
1539	    const table = manager.getOrCreateTable(table_name) catch return CmdError.OutOfMemory;
1540	    table.unbind(kr.key, kr.mods);
1541	}
