1547	fn cmdShowOptions(ctx: *Context, args: []const []const u8) CmdError!void {
1548	    var is_hooks = false;
1549	    var is_quiet = false;
1550	    var is_value_only = false;
1551	    var option_name: ?[]const u8 = null;
1552	
1553	    var i: usize = 0;
1554	    while (i < args.len) : (i += 1) {
1555	        if (std.mem.eql(u8, args[i], "-H")) {
1556	            is_hooks = true;
1557	        } else if (std.mem.eql(u8, args[i], "-q")) {
1558	            is_quiet = true;
1559	        } else if (std.mem.eql(u8, args[i], "-v")) {
1560	            is_value_only = true;
1561	        } else if (std.mem.eql(u8, args[i], "-t") and i + 1 < args.len) {
1562	            i += 1;
1563	        } else if (std.mem.eql(u8, args[i], "-A") or std.mem.eql(u8, args[i], "-g") or
1564	            std.mem.eql(u8, args[i], "-p") or std.mem.eql(u8, args[i], "-s") or
1565	            std.mem.eql(u8, args[i], "-w"))
1566	        {
1567	            // scope flags
1568	        } else if (args[i].len > 0 and args[i][0] != '-') {
1569	            option_name = args[i];
1570	        }
1571	    }
1572	
1573	    const session = ctx.session orelse {
1574	        if (!is_quiet) return CmdError.SessionNotFound;
1575	        return;
1576	    };
1577	
1578	    if (is_hooks) {
1579	        const all_hooks = [_]hooks_mod.HookType{
1580	            .after_new_session,    .after_new_window,   .after_split_window,
1581	            .after_select_pane,    .after_select_window,.after_resize_pane,
1582	            .after_rename_session, .after_rename_window,.client_attached,
1583	            .client_detached,      .client_resized,     .pane_exited,
1584	            .pane_focus_in,        .pane_focus_out,     .window_linked,
1585	            .window_unlinked,      .session_closed,     .session_renamed,
1586	            .window_renamed,
1587	        };
1588	        for (all_hooks) |ht| {
1589	            const hn = hookTypeName(ht);
1590	            for (ctx.server.hook_registry.getHooks(ht)) |hook| {
1591	                if (is_value_only) {
1592	                    try writeOutput(ctx, "{s}\n", .{hook.command});
1593	                } else {
1594	                    try writeOutput(ctx, "{s} {s}\n", .{ hn, hook.command });
1595	                }
1596	            }
1597	        }
1598	        return;
1599	    }
1600	
1601	    if (option_name) |name| {
1602	        if (std.mem.eql(u8, name, "base-index")) {
1603	            if (is_value_only) try writeOutput(ctx, "{d}\n", .{session.options.base_index}) else try writeOutput(ctx, "base-index {d}\n", .{session.options.base_index});
1604	        } else if (std.mem.eql(u8, name, "mouse")) {
1605	            const v = if (session.options.mouse) "on" else "off";
1606	            if (is_value_only) try writeOutput(ctx, "{s}\n", .{v}) else try writeOutput(ctx, "mouse {s}\n", .{v});
1607	        } else if (std.mem.eql(u8, name, "status")) {
1608	            const v = if (session.options.status) "on" else "off";
1609	            if (is_value_only) try writeOutput(ctx, "{s}\n", .{v}) else try writeOutput(ctx, "status {s}\n", .{v});
1610	        } else if (std.mem.eql(u8, name, "prefix")) {
1611	            const pk = session.options.prefix_key;
1612	            if (pk >= 1 and pk <= 26) {
1613	                const ch: u8 = @intCast(pk + 'a' - 1);
1614	                if (is_value_only) try writeOutput(ctx, "C-{c}\n", .{ch}) else try writeOutput(ctx, "prefix C-{c}\n", .{ch});
1615	            }
1616	        } else if (std.mem.eql(u8, name, "default-shell")) {
1617	            if (is_value_only) try writeOutput(ctx, "{s}\n", .{session.options.default_shell}) else try writeOutput(ctx, "default-shell {s}\n", .{session.options.default_shell});
1618	        } else if (std.mem.eql(u8, name, "status-left")) {
1619	            if (is_value_only) try writeOutput(ctx, "{s}\n", .{session.options.status_left}) else try writeOutput(ctx, "status-left {s}\n", .{session.options.status_left});
1620	        } else if (std.mem.eql(u8, name, "status-right")) {
1621	            if (is_value_only) try writeOutput(ctx, "{s}\n", .{session.options.status_right}) else try writeOutput(ctx, "status-right {s}\n", .{session.options.status_right});
1622	        } else if (std.mem.eql(u8, name, "visual-activity")) {
1623	            const v = if (session.options.visual_activity) "on" else "off";
1624	            if (is_value_only) try writeOutput(ctx, "{s}\n", .{v}) else try writeOutput(ctx, "visual-activity {s}\n", .{v});
1625	        } else {
1626	            if (!is_quiet) return CmdError.CommandFailed;
1627	        }
1628	        return;
1629	    }
1630	
1631	    // Show all options
1632	    const pk = session.options.prefix_key;
1633	    try writeOutput(ctx, "base-index {d}\n", .{session.options.base_index});
1634	    try writeOutput(ctx, "default-shell {s}\n", .{session.options.default_shell});
1635	    try writeOutput(ctx, "mouse {s}\n", .{if (session.options.mouse) "on" else "off"});
1636	    if (pk >= 1 and pk <= 26) {
1637	        try writeOutput(ctx, "prefix C-{c}\n", .{@as(u8, @intCast(pk + 'a' - 1))});
1638	    }
1639	    try writeOutput(ctx, "status {s}\n", .{if (session.options.status) "on" else "off"});
1640	    try writeOutput(ctx, "status-left {s}\n", .{session.options.status_left});
1641	    try writeOutput(ctx, "status-right {s}\n", .{session.options.status_right});
1642	    try writeOutput(ctx, "visual-activity {s}\n", .{if (session.options.visual_activity) "on" else "off"});
1643	}
