1715	        } else if (std.mem.eql(u8, args[i], "-g")) {
1716	            // global: no-op, use session environ
1717	        } else if (std.mem.eql(u8, args[i], "-t") and i + 1 < args.len) {
1718	            i += 1;
1719	        } else if (args[i].len > 0 and args[i][0] != '-') {
1720	            filter = args[i];
