1724	    const session = ctx.session orelse return CmdError.SessionNotFound;
1725	
1726	    var iter = session.environ.vars.iterator();
1727	    while (iter.next()) |entry| {
1728	        const key = entry.key_ptr.*;
1729	        const ev = entry.value_ptr.*;
1730	
1731	        if (filter) |f| {
1732	            if (!std.mem.eql(u8, key, f)) continue;
1733	        }
1734	        if (!show_hidden and ev.hidden) continue;
