1736	        if (ev.value) |val| {
1737	            if (shell_format) {
1738	                try writeOutput(ctx, "export {s}={s};\n", .{ key, val });
1739	            } else {
1740	                try writeOutput(ctx, "{s}={s}\n", .{ key, val });
1741	            }
1742	        } else {
