1752	fn cmdLoadBuffer(ctx: *Context, args: []const []const u8) CmdError!void {
1753	    if (args.len == 0) return CmdError.InvalidArgs;
1754	    const path = args[args.len - 1];
1755	    const buffer_name = parseNamedOption(args, "-b");
1756	    // -w: send to clipboard via OSC 52 (not yet wired to output path, data still pushed to stack)
1757	    // -t target-client: uses server default (multi-client targeting not yet implemented)
1758	
1759	    // Support '-' for reading from stdin (fd 0).
1760	    const is_stdin = std.mem.eql(u8, path, "-");
1761	    const fd: std.c.fd_t = if (is_stdin) 0 else blk: {
1762	        var path_buf: [4096]u8 = .{0} ** 4096;
1763	        if (path.len >= path_buf.len) return CmdError.CommandFailed;
1764	        @memcpy(path_buf[0..path.len], path);
1765	        const cpath: [*:0]const u8 = @ptrCast(path_buf[0..path.len :0]);
1766	        const file_fd = std.c.open(cpath, .{ .ACCMODE = .RDONLY }, @as(std.c.mode_t, 0));
1767	        if (file_fd < 0) return CmdError.CommandFailed;
1768	        break :blk file_fd;
1769	    };
1770	    defer {
1771	        if (!is_stdin) _ = std.c.close(fd);
1772	    }
1773	
1774	    var content_buf: [65536]u8 = undefined;
1775	    var total: usize = 0;
1776	    while (total < content_buf.len) {
1777	        const n = std.c.read(fd, content_buf[total..].ptr, content_buf.len - total);
1778	        if (n <= 0) break;
1779	        total += @intCast(n);
1780	    }
1781	    if (total == 0) return;
1782	
1783	    ctx.server.paste_stack.push(content_buf[0..total], buffer_name) catch return CmdError.OutOfMemory;
1784	}
