1795	
1796	    var path_buf: [4096]u8 = .{0} ** 4096;
1797	    if (path.len >= path_buf.len) return CmdError.CommandFailed;
1798	    @memcpy(path_buf[0..path.len], path);
1799	    const cpath: [*:0]const u8 = @ptrCast(path_buf[0..path.len :0]);
1800	
1801	    const flags: std.c.O = if (append)
1802	        .{ .ACCMODE = .WRONLY, .APPEND = true, .CREAT = true }
