1970	fn cmdSelectPane(ctx: *Context, args: []const []const u8) CmdError!void {
1971	    const session = ctx.session orelse return CmdError.SessionNotFound;
1972	    const window = session.active_window orelse return CmdError.WindowNotFound;
1973	
1974	    var i: usize = 0;
1975	    while (i < args.len) : (i += 1) {
1976	        if (std.mem.eql(u8, args[i], "-l")) {
1977	            // Select last active pane
1978	            if (window.last_pane) |last| {
1979	                for (window.panes.items) |p| {
1980	                    if (p == last) { window.selectPane(last); return; }
1981	                }
1982	            }
1983	            window.prevPane();
1984	            return;
1985	        } else if (std.mem.eql(u8, args[i], "-d")) {
1986	            if (window.active_pane) |pane| pane.flags.input_disabled = true;
1987	            return;
1988	        } else if (std.mem.eql(u8, args[i], "-e")) {
1989	            if (window.active_pane) |pane| pane.flags.input_disabled = false;
1990	            return;
1991	        } else if (std.mem.eql(u8, args[i], "-Z")) {
1992	            // keep zoom: selectPane preserves zoom already
1993	        } else if (std.mem.eql(u8, args[i], "-M") or std.mem.eql(u8, args[i], "-m")) {
1994	            // set/clear mark: not implemented
1995	        } else if (std.mem.eql(u8, args[i], "-T") and i + 1 < args.len) {
1996	            i += 1; // title: not implemented
1997	        } else if (std.mem.eql(u8, args[i], "-t") and i + 1 < args.len) {
1998	            i += 1;
1999	            const target = args[i];
2000	            if (std.mem.eql(u8, target, ":.+") or std.mem.eql(u8, target, ":+")) {
2001	                window.nextPane();
2002	                return;
2003	            }
2004	            if (std.mem.eql(u8, target, ":-") or std.mem.eql(u8, target, ":.-")) {
2005	                window.prevPane();
2006	                return;
2007	            }
2008	            if (target.len >= 2 and target[0] == '%') {
2009	                const pane_id = std.fmt.parseInt(u32, target[1..], 10) catch return CmdError.InvalidArgs;
2010	                if (!window.selectPaneById(pane_id)) return CmdError.PaneNotFound;
2011	                return;
2012	            }
2013	            const pane_index = std.fmt.parseInt(usize, target, 10) catch return CmdError.InvalidArgs;
2014	            if (!window.selectPaneByIndex(pane_index)) return CmdError.PaneNotFound;
2015	            return;
2016	        } else if (std.mem.eql(u8, args[i], "-U") or std.mem.eql(u8, args[i], "-L")) {
2017	            window.prevPane();
2018	            return;
2019	        } else if (std.mem.eql(u8, args[i], "-D") or std.mem.eql(u8, args[i], "-R")) {
2020	            window.nextPane();
2021	            return;
2022	        }
2023	    }
2024	
2025	    window.nextPane();
2026	}
