2065	    // -E shell-command: run on detach (not implemented, ignored)
2066	    _ = parseNamedOption(args, "-E");
2067	
2068	    var detach_all = false;
2069	    for (args) |arg| {
2070	        if (std.mem.eql(u8, arg, "-a")) detach_all = true;
2071	    }
2072	
2073	    // -s target-session: detach all clients of that session
2074	    if (parseNamedOption(args, "-s")) |session_name| {
2075	        const session = ctx.server.findSession(session_name) orelse return CmdError.SessionNotFound;
2076	        for (ctx.server.clients.items, 0..) |client, i| {
2077	            if (client.session == session) ctx.server.detachClient(i);
2078	        }
2079	        return;
2080	    }
2081	
2082	    // -t target-client (by index): detach it (or all except it with -a)
2083	    if (parseNamedOption(args, "-t")) |target| {
2084	        const idx = std.fmt.parseInt(usize, target, 10) catch return CmdError.InvalidArgs;
2085	        if (idx >= ctx.server.clients.items.len) return CmdError.CommandFailed;
2086	        if (detach_all) {
2087	            for (ctx.server.clients.items, 0..) |_, i| {
2088	                if (i != idx) ctx.server.detachClient(i);
2089	            }
2090	        } else {
2091	            ctx.server.detachClient(idx);
2092	        }
2093	        return;
2094	    }
2095	
2096	    // Default: detach all clients attached to the current session
2097	    const session = ctx.session orelse return CmdError.SessionNotFound;
2098	    for (ctx.server.clients.items, 0..) |client, i| {
2099	        if (client.session == session) ctx.server.detachClient(i);
2100	    }
