2113	fn cmdSendKeys(ctx: *Context, args: []const []const u8) CmdError!void {
2114	    // Parse flags: -l (literal), -H (hex byte per arg), -R (reset terminal),
2115	    // -X cmd (copy-mode command), -N count (repeat), -c/-t (target, ignored),
2116	    // -F/-K/-M (format/key-lookup/mouse, noted but no-op).
2117	    var literal = false;
2118	    var hex_mode = false;
2119	    var reset_terminal = false;
2120	    var copy_mode_cmd: ?[]const u8 = null;
2121	    var repeat_count: u32 = 1;
2122	
2123	    var i: usize = 0;
2124	    while (i < args.len) {
2125	        const arg = args[i];
2126	        if (std.mem.eql(u8, arg, "-l")) {
2127	            literal = true;
2128	            i += 1;
2129	        } else if (std.mem.eql(u8, arg, "-H")) {
2130	            hex_mode = true;
2131	            i += 1;
2132	        } else if (std.mem.eql(u8, arg, "-R")) {
2133	            reset_terminal = true;
2134	            i += 1;
2135	        } else if (std.mem.eql(u8, arg, "-F") or std.mem.eql(u8, arg, "-K") or std.mem.eql(u8, arg, "-M")) {
2136	            i += 1;
2137	        } else if (std.mem.eql(u8, arg, "-X")) {
2138	            i += 1;
2139	            if (i < args.len) { copy_mode_cmd = args[i]; i += 1; }
2140	        } else if (std.mem.eql(u8, arg, "-N")) {
2141	            i += 1;
2142	            if (i < args.len) { repeat_count = std.fmt.parseInt(u32, args[i], 10) catch 1; i += 1; }
2143	        } else if (std.mem.eql(u8, arg, "-c") or std.mem.eql(u8, arg, "-t")) {
2144	            i += 2;
2145	        } else {
2146	            break;
2147	        }
2148	    }
2149	    const key_args = args[i..];
2150	
2151	    if (reset_terminal) {
2152	        if (ctx.session) |rs| {
2153	            if (rs.active_window) |rw| {
2154	                if (rw.active_pane) |rp| {
2155	                    if (rp.fd >= 0) _ = std.c.write(rp.fd, "\x1bc", 2);
2156	                }
2157	            }
2158	        }
2159	    }
2160	
2161	    if (copy_mode_cmd) |cmd_str| {
2162	        const session = ctx.session orelse return CmdError.SessionNotFound;
2163	        const window = session.active_window orelse return CmdError.WindowNotFound;
2164	        const active_pane = window.active_pane orelse return CmdError.PaneNotFound;
2165	        _ = try handleCopyModeKey(ctx, active_pane, cmd_str);
2166	        return;
2167	    }
2168	
2169	    if (ctx.server.choose_tree_state != null) {
2170	        for (key_args) |key_str| {
2171	            if (try handleChooseTreeKey(ctx, null, key_str)) continue;
2172	        }
2173	        return;
2174	    }
2175	
2176	    const session = ctx.session orelse return CmdError.SessionNotFound;
2177	    const window = session.active_window orelse return CmdError.WindowNotFound;
2178	    const pane = window.active_pane orelse return CmdError.PaneNotFound;
2179	    if (pane.fd < 0) return CmdError.CommandFailed;
2180	
2181	    var rep: u32 = 0;
2182	    while (rep < repeat_count) : (rep += 1) {
2183	        for (key_args) |key_str| {
2184	            if (pane.prompt_state != null and try handlePromptKey(ctx, pane, key_str)) continue;
2185	            if (try handleChooseTreeKey(ctx, pane, key_str)) continue;
2186	            if (pane.copy_state != null and try handleCopyModeKey(ctx, pane, key_str)) continue;
2187	
