    // -X cmd (copy-mode command), -N count (repeat), -c/-t (target, ignored),
    // -F/-K/-M (format/key-lookup/mouse, noted but no-op).
    var literal = false;
    var hex_mode = false;
    var reset_terminal = false;
    var copy_mode_cmd: ?[]const u8 = null;
    var repeat_count: u32 = 1;

    var i: usize = 0;
    while (i < args.len) {
        const arg = args[i];
