2509	    var i: usize = 0;
2510	    while (i < args.len) : (i += 1) {
2511	        if (std.mem.eql(u8, args[i], "-U")) {
2512	            direction = .prev;
2513	        } else if (std.mem.eql(u8, args[i], "-D")) {
2514	            direction = .next;
2515	        } else if (std.mem.eql(u8, args[i], "-d") or std.mem.eql(u8, args[i], "-Z")) {
2516	            // no-select / keep-zoom: no special action in basic impl
2517	        } else if (std.mem.eql(u8, args[i], "-s") and i + 1 < args.len) {
2518	            i += 1;
2519	            src_spec = args[i];
2520	        } else if (std.mem.eql(u8, args[i], "-t") and i + 1 < args.len) {
2521	            i += 1;
2522	            dst_spec = args[i];
2523	        }
2524	    }
2525	
2526	    if (src_spec != null or dst_spec != null) {
2527	        const resolve = struct {
2528	            fn pane(win: *Window, spec: []const u8) ?*Pane {
2529	                if (spec.len >= 2 and spec[0] == '%') {
2530	                    const pid = std.fmt.parseInt(u32, spec[1..], 10) catch return null;
2531	                    for (win.panes.items) |p| { if (p.id == pid) return p; }
2532	                } else {
2533	                    const idx = std.fmt.parseInt(usize, spec, 10) catch return null;
2534	                    if (idx < win.panes.items.len) return win.panes.items[idx];
2535	                }
2536	                return null;
2537	            }
2538	        }.pane;
2539	
2540	        const src = if (src_spec) |s| resolve(window, s) else window.active_pane;
2541	        const dst = if (dst_spec) |s| resolve(window, s) else window.active_pane;
2542	        const sp = src orelse return CmdError.PaneNotFound;
2543	        const dp = dst orelse return CmdError.PaneNotFound;
2544	        if (sp == dp) return;
2545	
2546	        var src_idx: ?usize = null;
2547	        var dst_idx: ?usize = null;
2548	        for (window.panes.items, 0..) |p, idx| {
2549	            if (p == sp) src_idx = idx;
2550	            if (p == dp) dst_idx = idx;
2551	        }
2552	        const si = src_idx orelse return CmdError.PaneNotFound;
2553	        const di = dst_idx orelse return CmdError.PaneNotFound;
2554	
2555	        window.panes.items[si] = dp;
2556	        window.panes.items[di] = sp;
2557	
2558	        const tmp_xoff = sp.xoff; const tmp_yoff = sp.yoff;
2559	        const tmp_sx = sp.sx; const tmp_sy = sp.sy;
2560	        sp.xoff = dp.xoff; sp.yoff = dp.yoff; sp.sx = dp.sx; sp.sy = dp.sy;
2561	        dp.xoff = tmp_xoff; dp.yoff = tmp_yoff; dp.sx = tmp_sx; dp.sy = tmp_sy;
2562	        sp.flags.redraw = true;
2563	        dp.flags.redraw = true;
2564	        return;
2565	    }
2566	
2567	    window.swapActivePane(direction);
2568	}
