3809	            // -a (after), -b (before), -k (kill if exists): positional flags noted
3810	        } else if (std.mem.eql(u8, args[i], "-d")) {
3811	            no_select = true;
3812	        } else if (std.mem.eql(u8, args[i], "-s") and i + 1 < args.len) {
3813	            i += 1;
3814	            src_target = args[i];
3815	        } else if (std.mem.eql(u8, args[i], "-t") and i + 1 < args.len) {
3816	            i += 1;
3817	            dst_target = args[i];
3818	        }
3819	    }
3820	
3821	    const src_window = if (src_target) |t| blk: {
3822	        const num = std.fmt.parseInt(u32, t, 10) catch return CmdError.InvalidArgs;
3823	        break :blk session.findWindowByNumber(num) orelse return CmdError.WindowNotFound;
3824	    } else session.active_window orelse return CmdError.WindowNotFound;
3825	
3826	    // Destination session: try to parse "session:window" or session name
3827	    const dst_session = if (dst_target) |t| blk: {
3828	        // Check for colon-separated "session:window" format
3829	        if (std.mem.indexOfScalar(u8, t, ':')) |colon| {
3830	            break :blk ctx.server.findSession(t[0..colon]) orelse session;
3831	        }
3832	        break :blk ctx.server.findSession(t) orelse session;
3833	    } else session;
3834	
3835	    // Create a new window with the same name in the destination session
3836	    const new_window = Window.init(ctx.allocator, src_window.name, src_window.sx, src_window.sy) catch return CmdError.OutOfMemory;
3837	    errdefer new_window.deinit();
3838	
3839	    const pane = spawnWindowPane(ctx.allocator, defaultShellFromContext(ctx), new_window.sx, new_window.sy) catch |err| switch (err) {
3840	        CmdError.OutOfMemory => return CmdError.OutOfMemory,
3841	        else => return CmdError.CommandFailed,
3842	    };
3843	    errdefer pane.deinit();
3844	
3845	    new_window.addPane(pane) catch return CmdError.OutOfMemory;
3846	    dst_session.addWindow(new_window) catch return CmdError.OutOfMemory;
3847	    if (!no_select) dst_session.selectWindow(new_window);
3848	    ctx.server.trackPane(pane, new_window.sx, new_window.sy) catch return CmdError.CommandFailed;
3849	}
