3851	fn cmdMoveWindow(ctx: *Context, args: []const []const u8) CmdError!void {
3852	    const session = ctx.session orelse return CmdError.SessionNotFound;
3853	    var no_select = false;
3854	    var renumber = false;
3855	    var src_target: ?[]const u8 = null;
3856	    var dst_target: ?[]const u8 = null;
3857	    var i: usize = 0;
3858	    while (i < args.len) : (i += 1) {
3859	        if (std.mem.eql(u8, args[i], "-d")) {
3860	            no_select = true;
3861	        } else if (std.mem.eql(u8, args[i], "-r")) {
3862	            renumber = true;
3863	        } else if (std.mem.eql(u8, args[i], "-a") or std.mem.eql(u8, args[i], "-b") or
3864	            std.mem.eql(u8, args[i], "-k"))
3865	        {
3866	            // positional flags noted
3867	        } else if (std.mem.eql(u8, args[i], "-s") and i + 1 < args.len) {
3868	            i += 1;
3869	            src_target = args[i];
3870	        } else if (std.mem.eql(u8, args[i], "-t") and i + 1 < args.len) {
3871	            i += 1;
3872	            dst_target = args[i];
3873	        }
3874	    }
3875	
3876	    // Resolve source window
3877	    const src_window = if (src_target) |t| blk: {
3878	        const num = std.fmt.parseInt(u32, t, 10) catch return CmdError.InvalidArgs;
3879	        break :blk session.findWindowByNumber(num) orelse return CmdError.WindowNotFound;
3880	    } else session.active_window orelse return CmdError.WindowNotFound;
3881	
3882	    // Resolve destination session
3883	    const dst_session = if (dst_target) |t| blk: {
3884	        if (std.mem.indexOfScalar(u8, t, ':')) |colon| {
3885	            break :blk ctx.server.findSession(t[0..colon]) orelse session;
3886	        }
3887	        break :blk ctx.server.findSession(t) orelse session;
3888	    } else session;
3889	
3890	    if (dst_session == session) {
3891	        // Same session: just reorder (move to end)
3892	        for (session.windows.items, 0..) |w, idx| {
3893	            if (w == src_window) {
3894	                _ = session.windows.orderedRemove(idx);
3895	                break;
3896	            }
3897	        }
3898	        session.windows.append(session.allocator, src_window) catch return CmdError.OutOfMemory;
3899	        if (!no_select) session.selectWindow(src_window);
3900	        return;
3901	    }
3902	
3903	    // Cross-session move: remove from src session, add to dst session
3904	    for (session.windows.items, 0..) |w, idx| {
3905	        if (w == src_window) {
3906	            _ = session.windows.orderedRemove(idx);
3907	            break;
3908	        }
3909	    }
3910	    if (session.active_window == src_window) {
3911	        session.active_window = if (session.windows.items.len > 0) session.windows.items[0] else null;
3912	    }
3913	
3914	    dst_session.addWindow(src_window) catch return CmdError.OutOfMemory;
3915	    if (!no_select) dst_session.selectWindow(src_window);
3916	}
