3918	fn cmdResizeWindow(ctx: *Context, args: []const []const u8) CmdError!void {
3919	    const session = ctx.session orelse return CmdError.SessionNotFound;
3920	    var window = session.active_window orelse return CmdError.WindowNotFound;
3921	    var dx: i32 = 0;
3922	    var dy: i32 = 0;
3923	    var abs_x: ?u32 = null;
3924	    var abs_y: ?u32 = null;
3925	    var amount: u32 = 1;
3926	    var i: usize = 0;
3927	    while (i < args.len) : (i += 1) {
3928	        if (std.mem.eql(u8, args[i], "-U")) {
3929	            dy = -1;
3930	        } else if (std.mem.eql(u8, args[i], "-D")) {
3931	            dy = 1;
3932	        } else if (std.mem.eql(u8, args[i], "-L")) {
3933	            dx = -1;
3934	        } else if (std.mem.eql(u8, args[i], "-R")) {
3935	            dx = 1;
3936	        } else if (std.mem.eql(u8, args[i], "-a") or std.mem.eql(u8, args[i], "-A")) {
3937	            // -a: fit smallest client, -A: fit largest client — no-op (no client dims tracked)
3938	        } else if (std.mem.eql(u8, args[i], "-x") and i + 1 < args.len) {
3939	            i += 1;
3940	            abs_x = std.fmt.parseInt(u32, args[i], 10) catch null;
3941	        } else if (std.mem.eql(u8, args[i], "-y") and i + 1 < args.len) {
3942	            i += 1;
3943	            abs_y = std.fmt.parseInt(u32, args[i], 10) catch null;
3944	        } else if (std.mem.eql(u8, args[i], "-t") and i + 1 < args.len) {
3945	            i += 1;
3946	            const num = std.fmt.parseInt(u32, args[i], 10) catch return CmdError.InvalidArgs;
3947	            window = session.findWindowByNumber(num) orelse return CmdError.WindowNotFound;
3948	        } else {
3949	            amount = std.fmt.parseInt(u32, args[i], 10) catch amount;
3950	        }
3951	    }
3952	
3953	    const new_sx = if (abs_x) |x| x else if (dx < 0)
3954	        @max(1, window.sx -| amount)
3955	    else if (dx > 0)
3956	        window.sx + amount
3957	    else
3958	        window.sx;
3959	
3960	    const new_sy = if (abs_y) |y| y else if (dy < 0)
3961	        @max(1, window.sy -| amount)
3962	    else if (dy > 0)
3963	        window.sy + amount
3964	    else
3965	        window.sy;
3966	
3967	    if (new_sx == window.sx and new_sy == window.sy) return;
3968	    window.resize(new_sx, new_sy);
3969	}
