3971	fn cmdRespawnWindow(ctx: *Context, args: []const []const u8) CmdError!void {
3972	    const session = ctx.session orelse return CmdError.SessionNotFound;
3973	    var kill_running = false;
3974	    var target_num: ?u32 = null;
3975	    var i: usize = 0;
3976	    while (i < args.len) : (i += 1) {
3977	        if (std.mem.eql(u8, args[i], "-k")) {
3978	            kill_running = true;
3979	        } else if (std.mem.eql(u8, args[i], "-t") and i + 1 < args.len) {
3980	            i += 1;
3981	            target_num = std.fmt.parseInt(u32, args[i], 10) catch null;
3982	        } else if ((std.mem.eql(u8, args[i], "-c") or std.mem.eql(u8, args[i], "-e")) and i + 1 < args.len) {
3983	            i += 1; // consume -c dir / -e env value
3984	        }
3985	    }
3986	
3987	    const window = if (target_num) |n|
3988	        session.findWindowByNumber(n) orelse return CmdError.WindowNotFound
3989	    else
3990	        session.active_window orelse return CmdError.WindowNotFound;
3991	
3992	    const pane = window.active_pane orelse return CmdError.PaneNotFound;
3993	
3994	    // Kill running process if requested or if already exited
3995	    if (kill_running and pane.pid > 0) {
3996	        _ = std.c.kill(pane.pid, .TERM);
3997	        _ = std.c.waitpid(pane.pid, null, 0);
3998	        pane.pid = 0;
3999	    } else if (!kill_running and pane.pid > 0) {
4000	        // Check if still running; refuse if process is alive
4001	        if (std.c.kill(pane.pid, @enumFromInt(0)) == 0) {
4002	            try writeReplyMessage(ctx, .error_msg, "respawn-window: pane still active (use -k to force)\n");
4003	            return CmdError.CommandFailed;
4004	        }
4005	    }
4006	
4007	    // Close old fd
4008	    if (pane.fd >= 0) {
4009	        ctx.server.untrackPane(pane.id);
4010	        _ = std.c.close(pane.fd);
4011	        pane.fd = -1;
4012	    }
4013	
4014	    // Spawn a fresh PTY
4015	    const shell = defaultShellFromContext(ctx);
4016	    var pty = Pty.openPty() catch return CmdError.CommandFailed;
4017	    pty.forkExec(shell, null) catch return CmdError.CommandFailed;
4018	    pty.resize(@intCast(pane.sx), @intCast(pane.sy));
4019	    pane.fd = pty.master_fd;
4020	    pane.pid = pty.pid;
4021	    pane.flags.exited = false;
4022	    ctx.server.trackPane(pane, pane.sx, pane.sy) catch return CmdError.CommandFailed;
4023	}
