4025	fn cmdUnlinkWindow(ctx: *Context, args: []const []const u8) CmdError!void {
4026	    const session = ctx.session orelse return CmdError.SessionNotFound;
4027	    var kill_if_last = false;
4028	    var target_num: ?u32 = null;
4029	    var i: usize = 0;
4030	    while (i < args.len) : (i += 1) {
4031	        if (std.mem.eql(u8, args[i], "-k")) {
4032	            kill_if_last = true;
4033	        } else if (std.mem.eql(u8, args[i], "-t") and i + 1 < args.len) {
4034	            i += 1;
4035	            target_num = std.fmt.parseInt(u32, args[i], 10) catch null;
4036	        }
4037	    }
4038	
4039	    const window = if (target_num) |n|
4040	        session.findWindowByNumber(n) orelse return CmdError.WindowNotFound
4041	    else
4042	        session.active_window orelse return CmdError.WindowNotFound;
4043	
4044	    if (kill_if_last) {
4045	        for (window.panes.items) |pane| ctx.server.untrackPane(pane.id);
4046	        const session_empty = session.removeWindow(window);
4047	        if (session_empty) {
4048	            ctx.session = null;
4049	            ctx.server.removeSession(session);
4050	        }
4051	    } else {
4052	        // Remove window from session without destroying it (tmux semantics:
4053	        // destroy only if this is the last link). Since we have no real linking,
4054	        // just remove from session list and deinit.
4055	        for (window.panes.items) |pane| ctx.server.untrackPane(pane.id);
4056	        const session_empty = session.removeWindow(window);
4057	        if (session_empty) {
4058	            ctx.session = null;
4059	            ctx.server.removeSession(session);
4060	        }
4061	    }
4062	}
