1	const std = @import("std");
2	
3	/// Key binding action.
4	pub const Action = union(enum) {
5	    /// Run a tmux command string.
6	    command: []const u8,
7	    /// No-op (unbound).
8	    none,
9	};
10	
11	/// A single key binding.
12	pub const Binding = struct {
13	    key: u21,
14	    modifiers: Modifiers,
15	    action: Action,
16	    note: ?[]const u8 = null,
17	    repeat: bool = false,
18	};
19	
20	pub const Modifiers = packed struct(u8) {
21	    ctrl: bool = false,
22	    meta: bool = false,
23	    shift: bool = false,
24	    _padding: u5 = 0,
25	
26	    pub const none: Modifiers = .{};
27	};
28	
29	/// A key table (e.g., "prefix", "root", "copy-mode-vi").
30	pub const KeyTable = struct {
31	    name: []const u8,
32	    bindings: std.ArrayListAligned(Binding, null),
33	    allocator: std.mem.Allocator,
34	
35	    pub fn init(alloc: std.mem.Allocator, name: []const u8) KeyTable {
36	        return .{
37	            .name = name,
38	            .bindings = .empty,
39	            .allocator = alloc,
40	        };
41	    }
42	
43	    pub fn deinit(self: *KeyTable) void {
44	        for (self.bindings.items) |*b| {
45	            switch (b.action) {
46	                .command => |cmd| self.allocator.free(cmd),
47	                .none => {},
48	            }
49	            if (b.note) |n| self.allocator.free(n);
50	        }
51	        self.bindings.deinit(self.allocator);
52	    }
53	
54	    /// Bind a key to a command.
55	    pub fn bind(self: *KeyTable, key: u21, mods: Modifiers, command: []const u8) !void {
56	        try self.bindFull(key, mods, command, null, false);
57	    }
58	
59	    /// Bind a key with optional note and repeat flag.
60	    pub fn bindFull(self: *KeyTable, key: u21, mods: Modifiers, command: []const u8, note: ?[]const u8, repeat: bool) !void {
61	        self.unbind(key, mods);
62	        const owned_cmd = try self.allocator.dupe(u8, command);
63	        errdefer self.allocator.free(owned_cmd);
64	        const owned_note: ?[]const u8 = if (note) |n| try self.allocator.dupe(u8, n) else null;
65	        try self.bindings.append(self.allocator, .{
66	            .key = key,
67	            .modifiers = mods,
68	            .action = .{ .command = owned_cmd },
69	            .note = owned_note,
70	            .repeat = repeat,
71	        });
72	    }
73	
74	    /// Unbind a key.
75	    pub fn unbind(self: *KeyTable, key: u21, mods: Modifiers) void {
76	        var i: usize = 0;
77	        while (i < self.bindings.items.len) {
78	            const b = &self.bindings.items[i];
79	            if (b.key == key and @as(u8, @bitCast(b.modifiers)) == @as(u8, @bitCast(mods))) {
80	                switch (b.action) {
81	                    .command => |cmd| self.allocator.free(cmd),
82	                    .none => {},
83	                }
84	                _ = self.bindings.orderedRemove(i);
85	            } else {
86	                i += 1;
87	            }
88	        }
89	    }
90	
91	    /// Look up a binding.
92	    pub fn lookup(self: *const KeyTable, key: u21, mods: Modifiers) ?Action {
93	        for (self.bindings.items) |b| {
94	            if (b.key == key and @as(u8, @bitCast(b.modifiers)) == @as(u8, @bitCast(mods))) {
95	                return b.action;
96	            }
97	        }
98	        return null;
99	    }
100	};
101	
102	/// Key binding manager with multiple tables.
103	pub const BindingManager = struct {
104	    tables: std.StringHashMap(KeyTable),
105	    prefix_key: u21,
106	    prefix_mods: Modifiers,
107	    in_prefix: bool,
108	    allocator: std.mem.Allocator,
109	
110	    pub fn init(alloc: std.mem.Allocator) BindingManager {
111	        return .{
