    attached: u32,
    flags: Flags,

    options: Options,
    environ: Environ,

    allocator: std.mem.Allocator,

    pub const Flags = packed struct(u8) {
        alerted: bool = false,
        _padding: u7 = 0,
    };

    pub const Options = struct {
        base_index: u32 = 0,
        default_shell: [:0]u8,
