        if (self.active_window) |active| {
            for (self.windows.items, 0..) |w, i| {
                if (w == active) {
                    const prev_idx = if (i == 0) self.windows.items.len - 1 else i - 1;
                    self.active_window = self.windows.items[prev_idx];
                    return;
                }
            }
