            session_level = true;
        } else if ((std.mem.eql(u8, args[i], "-F") or std.mem.eql(u8, args[i], "-f") or std.mem.eql(u8, args[i], "-t")) and i + 1 < args.len) {
            i += 1; // format/filter/target: not implemented
