179	            gcd.dispatch_source_set_event_handler_f(src, fdReadHandler);
180	            gcd.dispatch_resume(src);
181	            gop.value_ptr.read = fc;
182	        }
183	        if (ev == .write or ev == .read_write) {
184	            if (gop.value_ptr.write) |old| cancelFdContext(old);
185	            const fc = try self.allocator.create(FdContext);
186	            const src = gcd.dispatch_source_create(sourceTypeWrite(), @intCast(fd), 0, self.queue);
187	            if (src == null) {
188	                self.allocator.destroy(fc);
189	                return error.SourceCreateFailed;
190	            }
191	            fc.* = .{ .fd = fd, .event_type = .write, .callback = cb, .source = src };
192	            gcd.dispatch_set_context(src, fc);
193	            gcd.dispatch_source_set_event_handler_f(src, fdWriteHandler);
194	            gcd.dispatch_resume(src);
