253	    pub fn deinit(self: *GcdEventLoop) void {
254	        var fd_it = self.fd_sources.iterator();
255	        while (fd_it.next()) |kv| {
256	            if (kv.value_ptr.read) |fc| {
257	                cancelFdContext(fc);
258	                self.allocator.destroy(fc);
259	            }
260	            if (kv.value_ptr.write) |fc| {
261	                cancelFdContext(fc);
262	                self.allocator.destroy(fc);
263	            }
264	        }
265	        self.fd_sources.deinit();
266	
267	        var timer_it = self.timer_sources.iterator();
268	        while (timer_it.next()) |kv| {
269	            gcd.dispatch_source_cancel(kv.value_ptr.*.source);
270	            gcd.dispatch_release(kv.value_ptr.*.source);
271	            self.allocator.destroy(kv.value_ptr.*);
272	        }
273	        self.timer_sources.deinit();
274	
275	        if (self.stop_sem) |s| gcd.dispatch_release(s);
276	        if (self.queue) |q| gcd.dispatch_release(q);
277	    }
278	
279	    // ---- Helpers ------------------------------------------------------------
