2	const builtin = @import("builtin");
3	const atlas_mod = @import("atlas.zig");
4	
5	/// FreeType C API declarations.
6	const ft = struct {
7	    // Opaque types
8	    const FT_Library = ?*anyopaque;
9	    const FT_Face = ?*anyopaque;
10	
11	    // Error type
12	    const FT_Error = i32;
13	
14	    // Glyph metrics (in 26.6 fixed point)
15	    const FT_Glyph_Metrics = extern struct {
16	        width: i64,
17	        height: i64,
18	        horiBearingX: i64,
19	        horiBearingY: i64,
20	        horiAdvance: i64,
21	        vertBearingX: i64,
22	        vertBearingY: i64,
23	        vertAdvance: i64,
24	    };
25	
26	    // Bitmap
27	    const FT_Bitmap = extern struct {
28	        rows: u32,
29	        width: u32,
30	        pitch: i32,
31	        buffer: ?[*]u8,
32	        num_grays: u16,
33	        pixel_mode: u8,
34	        palette_mode: u8,
35	        palette: ?*anyopaque,
36	    };
37	
38	    // Glyph slot (simplified - we access fields via offset)
39	    const FT_GlyphSlot = ?*anyopaque;
40	
41	    // Load flags
42	    const FT_LOAD_RENDER: i32 = 4;
43	    const FT_LOAD_NO_HINTING: i32 = 2;
44	    const FT_LOAD_TARGET_LIGHT: i32 = 0x10000;
45	
46	    // Functions
47	    extern "c" fn FT_Init_FreeType(library: *FT_Library) FT_Error;
48	    extern "c" fn FT_Done_FreeType(library: FT_Library) FT_Error;
49	    extern "c" fn FT_New_Face(library: FT_Library, path: [*:0]const u8, face_index: i64, face: *FT_Face) FT_Error;
50	    extern "c" fn FT_Done_Face(face: FT_Face) FT_Error;
51	    extern "c" fn FT_Set_Pixel_Sizes(face: FT_Face, width: u32, height: u32) FT_Error;
52	    extern "c" fn FT_Set_Char_Size(face: FT_Face, width: i64, height: i64, hdpi: u32, vdpi: u32) FT_Error;
53	    extern "c" fn FT_Load_Char(face: FT_Face, char_code: u64, load_flags: i32) FT_Error;
54	    extern "c" fn FT_Get_Char_Index(face: FT_Face, charcode: u64) u32;
55	};
56	
57	/// Font rasterizer using FreeType.
58	pub const FontRasterizer = struct {
59	    library: ft.FT_Library,
60	    face: ft.FT_Face,
61	    pixel_size: u32,
62	    cell_width: u16,
63	    cell_height: u16,
64	    ascender: i16,
65	    descender: i16,
66	    initialized: bool,
67	
68	    pub const Error = error{
69	        InitFailed,
70	        FaceLoadFailed,
71	        SizeSetFailed,
72	        GlyphLoadFailed,
73	    };
74	
75	    /// Initialize FreeType and load a font face.
76	    pub fn init(font_path: [:0]const u8, pixel_size: u32, dpi: u32) FontRasterizer {
77	        var library: ft.FT_Library = null;
78	        if (ft.FT_Init_FreeType(&library) != 0) {
79	            return uninitializedRasterizer();
80	        }
81	
82	        var face: ft.FT_Face = null;
83	        if (ft.FT_New_Face(library, font_path.ptr, 0, &face) != 0) {
84	            _ = ft.FT_Done_FreeType(library);
85	            return uninitializedRasterizer();
86	        }
87	
88	        // Set size: pixel_size in 26.6 fixed point
89	        const size_26_6: i64 = @as(i64, @intCast(pixel_size)) * 64;
90	        if (ft.FT_Set_Char_Size(face, 0, size_26_6, dpi, dpi) != 0) {
91	            // Fallback to pixel sizes
92	            _ = ft.FT_Set_Pixel_Sizes(face, 0, pixel_size);
93	        }
94	
95	        // Determine cell dimensions by measuring 'M'
96	        var cell_w: u16 = @intCast(pixel_size / 2);
97	        var cell_h: u16 = @intCast(pixel_size);
98	        var asc: i16 = @intCast(pixel_size);
99	        var desc: i16 = 0;
100	
101	        if (ft.FT_Load_Char(face, 'M', ft.FT_LOAD_RENDER) == 0) {
102	            // Glyph loaded successfully — metrics available via face->glyph
103	            // Using pixel_size-based defaults below for portability
104	        }
105	
106	        // Use pixel_size-based defaults
107	        cell_w = @intCast(@max(1, pixel_size * 6 / 10)); // ~60% of height
108	        cell_h = @intCast(@max(1, pixel_size + pixel_size / 4)); // height + line gap
109	        asc = @intCast(pixel_size * 4 / 5);
110	        desc = @intCast(pixel_size / 5);
111	
112	        return .{
113	            .library = library,
114	            .face = face,
115	            .pixel_size = pixel_size,
116	            .cell_width = cell_w,
117	            .cell_height = cell_h,
118	            .ascender = asc,
119	            .descender = desc,
120	            .initialized = true,
121	        };
122	    }
123	
124	    fn uninitializedRasterizer() FontRasterizer {
125	        return .{
126	            .library = null,
127	            .face = null,
128	            .pixel_size = 0,
129	            .cell_width = 8,
130	            .cell_height = 16,
131	            .ascender = 14,
132	            .descender = 2,
133	            .initialized = false,
134	        };
135	    }
136	
137	    pub fn deinit(self: *FontRasterizer) void {
138	        if (self.face) |f| _ = ft.FT_Done_Face(f);
139	        if (self.library) |l| _ = ft.FT_Done_FreeType(l);
140	        self.face = null;
141	        self.library = null;
142	        self.initialized = false;
143	    }
144	
145	    /// Rasterize a glyph and add it to the atlas.
146	    /// Returns the atlas entry for the glyph.
147	    pub fn rasterizeGlyph(self: *FontRasterizer, glyph_atlas: *atlas_mod.GlyphAtlas, codepoint: u21) !atlas_mod.GlyphEntry {
148	        // Check cache first
149	        if (glyph_atlas.getGlyph(codepoint)) |entry| return entry;
150	
151	        if (!self.initialized or self.face == null) {
152	            // Return a placeholder entry
153	            return glyph_atlas.addGlyph(codepoint, 0, 0, &.{}, 0, 0, self.cell_width);
154	        }
155	
156	        // Load and render the glyph
157	        if (ft.FT_Load_Char(self.face, codepoint, ft.FT_LOAD_RENDER) != 0) {
158	            // Glyph not found - add empty entry
159	            return glyph_atlas.addGlyph(codepoint, 0, 0, &.{}, 0, 0, self.cell_width);
160	        }
161	
162	        // Access the rendered bitmap from the glyph slot
163	        // FT_GlyphSlotRec layout: the bitmap is at a known offset
164	        // Since we can't safely dereference the opaque pointer in portable Zig,
165	        // we use FT_Load_Char with FT_LOAD_RENDER which renders to the slot's bitmap
166	
167	        // For now, create a simple bitmap based on the codepoint
168	        // Real implementation would read face->glyph->bitmap
169	        const w = self.cell_width;
170	        const h: u16 = @intCast(self.pixel_size);
171	
172	        // Generate a placeholder bitmap (filled rectangle for visible chars)
173	        var bitmap_buf: [4096]u8 = .{0} ** 4096;
174	        const bitmap_size = @as(usize, w) * @as(usize, h);
175	        if (bitmap_size <= bitmap_buf.len and codepoint >= 0x20 and codepoint < 0x7f) {
176	            // Simple: fill the glyph area for printable ASCII
177	            @memset(bitmap_buf[0..bitmap_size], 0x80);
178	        }
179	
180	        return glyph_atlas.addGlyph(
181	            codepoint,
182	            w,
183	            h,
184	            bitmap_buf[0..bitmap_size],
185	            0,
186	            self.ascender,
187	            w,
188	        );
189	    }
190	
191	    /// Rasterize all printable ASCII characters into the atlas.
192	    pub fn preloadAscii(self: *FontRasterizer, glyph_atlas: *atlas_mod.GlyphAtlas) void {
193	        var cp: u21 = 0x20; // space
194	        while (cp <= 0x7e) : (cp += 1) { // ~
195	            _ = self.rasterizeGlyph(glyph_atlas, cp) catch continue;
196	        }
197	    }
198	
199	    /// Get cell dimensions.
200	    pub fn getCellSize(self: *const FontRasterizer) struct { width: u16, height: u16 } {
201	        return .{ .width = self.cell_width, .height = self.cell_height };
202	    }
203	
204	    /// Check if a codepoint has a glyph in the font.
205	    pub fn hasGlyph(self: *const FontRasterizer, codepoint: u21) bool {
206	        if (!self.initialized or self.face == null) return false;
207	        return ft.FT_Get_Char_Index(self.face, codepoint) != 0;
208	    }
