pub fn run(self: *Server) !void {
    const max_fds = 256;
    var pollfds: [max_fds]std.c.pollfd = undefined;

    while (self.running) {
        if (signals.SignalHandler.shouldExit()) {
            self.stop();
            break;
        }

        var nfds: usize = 0;
        if (self.listen_fd >= 0) {
            pollfds[nfds] = .{ .fd = self.listen_fd, .events = POLLIN, .revents = 0 };
