1	// agentmux Metal Shader Library
2	// Terminal cell rendering with glyph atlas texture sampling
3	
4	#include <metal_stdlib>
5	using namespace metal;
6	
7	// Vertex input from CPU
8	struct VertexIn {
9	    float2 position  [[attribute(0)]];
10	    float2 texCoord  [[attribute(1)]];
11	    float4 fgColor   [[attribute(2)]];
12	    float4 bgColor   [[attribute(3)]];
13	    float  isGlyph   [[attribute(4)]]; // 1.0 = glyph quad, 0.0 = background quad
14	};
15	
16	// Vertex output / Fragment input
17	struct VertexOut {
18	    float4 position  [[position]];
19	    float2 texCoord;
20	    float4 fgColor;
21	    float4 bgColor;
22	    float  isGlyph;
23	};
24	
25	// Uniforms
26	struct Uniforms {
27	    float4x4 projectionMatrix;
28	    float2   viewportSize;
29	    float2   cellSize;
30	    float    time;
31	};
32	
33	// --- Vertex Shader ---
34	
35	vertex VertexOut vertex_main(
36	    VertexIn in [[stage_in]],
37	    constant Uniforms &uniforms [[buffer(1)]]
38	) {
39	    VertexOut out;
40	    out.position = uniforms.projectionMatrix * float4(in.position, 0.0, 1.0);
41	    out.texCoord = in.texCoord;
42	    out.fgColor = in.fgColor;
43	    out.bgColor = in.bgColor;
44	    out.isGlyph = in.isGlyph;
45	    return out;
46	}
47	
48	// --- Fragment Shader: Background ---
49	
50	fragment float4 fragment_background(
51	    VertexOut in [[stage_in]]
52	) {
53	    return in.bgColor;
54	}
55	
56	// --- Fragment Shader: Glyph ---
57	// Samples the glyph atlas texture and applies foreground color
58	
59	fragment float4 fragment_glyph(
60	    VertexOut in [[stage_in]],
61	    texture2d<float> atlasTexture [[texture(0)]],
62	    sampler atlasSampler [[sampler(0)]]
63	) {
64	    float alpha = atlasTexture.sample(atlasSampler, in.texCoord).r;
65	    if (alpha < 0.01) {
66	        discard_fragment();
67	    }
68	    return float4(in.fgColor.rgb, in.fgColor.a * alpha);
69	}
70	
71	// --- Fragment Shader: Combined Cell ---
72	// Renders background color, then composites glyph on top
73	
74	fragment float4 fragment_cell(
75	    VertexOut in [[stage_in]],
76	    texture2d<float> atlasTexture [[texture(0)]],
77	    sampler atlasSampler [[sampler(0)]]
78	) {
79	    if (in.isGlyph < 0.5) {
80	        // Background quad
81	        return in.bgColor;
